async (params, browser) => {
  // Open MyFitnessPal page
  await browser.open(`https://www.myfitnesspal.com/food/calories/${params.food_id}`)

  // Wait for page
  await browser.waitForSelector('.nutrition-facts, h1, [class*="nutrition"], .content', 15000)

  // Let page render
  await browser.wait(2500)

  // Extract data
  const result = await browser.evaluate(`const name = document.querySelector('h1, .food-name')?.textContent?.trim() || ''; const nutrition = {}; document.querySelectorAll('.nutrition-facts tr, [class*="nutrient"], dl dt, dl dd').forEach(el => { const label = el.querySelector('td:first-child, dt')?.textContent?.trim()?.toLowerCase() || ''; const value = el.querySelector('td:last-child, dd, .value')?.textContent?.trim() || ''; if (label) nutrition[label] = value; }); return { name, nutrition, url: window.location.href };`)

  return result
}
